import{_ as r,o as a,i,aB as o}from"./chunks/framework._ZAOES46.js";const h=JSON.parse('{"title":"搭配 UI 组件库","description":"","frontmatter":{},"headers":[],"relativePath":"guide/with-ui-libraries.md","filePath":"guide/with-ui-libraries.md"}'),t={name:"guide/with-ui-libraries.md"};function d(c,e,l,n,p,s){return a(),i("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/with-ui-libraries.md for this page in Markdown format</div><h1 id="搭配-ui-组件库" tabindex="-1">搭配 UI 组件库 <a class="header-anchor" href="#搭配-ui-组件库" aria-label="Permalink to “搭配 UI 组件库”">​</a></h1><h2 id="预设-ui-组件库" tabindex="-1">预设 UI 组件库 <a class="header-anchor" href="#预设-ui-组件库" aria-label="Permalink to “预设 UI 组件库”">​</a></h2><p>框架已为你集成好了以下 UI 组件库的工程，开箱即用，分别在 <code>apps/</code> 目录下的不同应用内：</p><ul><li><code>core-ant-design-vue</code> - <a href="https://www.antdv.com/" target="_blank" rel="noreferrer">Ant Design Vue</a></li><li><code>core-antdv-next</code> - <a href="https://www.antdv-next.com/" target="_blank" rel="noreferrer">Antdv Next</a></li><li><code>core-arco-design-vue</code> - <a href="https://arco.design/vue/" target="_blank" rel="noreferrer">Arco Design Vue</a></li><li><code>core-element-plus</code> - <a href="https://element-plus.org/" target="_blank" rel="noreferrer">Element Plus</a></li><li><code>core-naive-ui</code> - <a href="https://www.naiveui.com/" target="_blank" rel="noreferrer">Naive UI</a></li><li><code>core-tdesign</code> - <a href="https://tdesign.tencent.com/vue-next/" target="_blank" rel="noreferrer">Tdesign</a></li><li><code>core-vexip-ui</code> - <a href="https://www.vexipui.com/" target="_blank" rel="noreferrer">Vexip UI</a></li></ul><h2 id="接入其他-ui-组件库" tabindex="-1">接入其他 UI 组件库 <a class="header-anchor" href="#接入其他-ui-组件库" aria-label="Permalink to “接入其他 UI 组件库”">​</a></h2><p>如果你需要使用的 UI 组件库不在其中，也可以参考以下步骤自行接入其他 UI 组件库。</p><h3 id="_1-复制-core-应用" tabindex="-1">1. 复制 <code>core</code> 应用 <a class="header-anchor" href="#_1-复制-core-应用" aria-label="Permalink to “1. 复制 core 应用”">​</a></h3><p>复制 <code>apps/core</code> 应用，同时修改 <code>apps/&lt;app&gt;/package.json</code> 中 <code>name</code> 属性。</p><h3 id="_2-修改-apps-app-src-ui-provider-目录" tabindex="-1">2. 修改 <code>apps/&lt;app&gt;/src/ui/provider</code> 目录 <a class="header-anchor" href="#_2-修改-apps-app-src-ui-provider-目录" aria-label="Permalink to “2. 修改 apps/&lt;app&gt;/src/ui/provider 目录”">​</a></h3><p>这个目录是框架对接 UI 组件库的统一入口，一共只有 2 个文件：</p><ul><li><code>index.ts</code>：负责安装 UI 组件库，如果是专业版，并且组件库支持国际化，还需要导出该组件库的语言包映射</li><li><code>index.vue</code>：负责在根组件外层包裹全局 Provider，并把框架的主题、语言等状态同步给 UI 组件库</li></ul><p>框架之所以能方便切换 UI 组件库，核心原因就在这里：</p><ul><li><code>main.ts</code> 中通过 <code>app.use(uiProvider)</code> 安装 UI 组件库</li><li><code>App.vue</code> 中通过 <code>&lt;Provider&gt;</code> 包裹整棵应用</li></ul><p>因此大多数情况下，你只需要改这两个文件，<code>main.ts</code> 和 <code>App.vue</code> 本身不需要动。</p>',15)])])}const _=r(t,[["render",d]]);export{h as __pageData,_ as default};
